{% extends "base.html" %}

{% block content %}
<div class="row align-items-end mb-5 g-3">
    <div class="col-md-6">
        <h2 class="fw-800 mb-2">
            {% if q %}
                '{{ q }}' 검색 결과
            {% elif show_ended %}
                전체 이벤트 목록
            {% else %}
                현재 진행 중인 이벤트
            {% endif %}
        </h2>
        <p class="text-muted mb-0">실시간으로 업데이트되는 굿즈 재고 현황을 확인하세요.</p>
    </div>
    <div class="col-md-6">
        <form method="get" action="/" class="d-flex flex-column align-items-md-end gap-2">
            <div class="input-group" style="max_width: 400px;">
                <input type="text" name="q" class="form-control" placeholder="이벤트명 검색..." value="{{ q or '' }}">
                <button class="btn btn-dark" type="submit"><i class="bi bi-search"></i> 검색</button>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="showEnded" name="show_ended" value="true" 
                       {% if show_ended %}checked{% endif %} onchange="this.form.submit()">
                <label class="form-check-label user-select-none" for="showEnded">종료된 이벤트 포함</label>
            </div>
        </form>
    </div>
</div>

<div class="row row-cols-1 row-cols-lg-2 g-4">
    {% for item in events %}
    <div class="col">
        <div class="card h-100 event-card">
            <div class="card-img-container">
                {% if item.event.ImageUrl %}
                <img src="{{ item.event.ImageUrl }}" class="card-img-top" alt="{{ item.event.EventName }}">
                {% else %}
                <div class="card-img-top bg-light d-flex align-items-center justify-content-center">
                    <span class="text-muted">No Image</span>
                </div>
                {% endif %}
            </div>

            <div class="card-body p-4">
                <h5 class="card-title fw-bold mb-3 line-clamp-2" style="height: 3rem; line-height: 1.5;">
                    <a href="/event/{{ item.event.EventID }}" class="text-decoration-none stretched-link" style="color: var(--text-main);">
                        {{ item.event.EventName }}
                    </a>
                    {% if item.event.GiftID %}
                    <span class="ms-1 position-relative" style="font-size: 1rem; z-index: 2; cursor: help;" data-bs-toggle="tooltip" data-bs-placement="top" title="Gift ID: {{ item.event.GiftID }}">🎁</span>
                    {% endif %}
                </h5>
                <p class="text-muted small mb-4">
                    <i class="bi bi-calendar-event me-1"></i>
                    {{ item.event.ProgressStartDate }} — {{ item.event.ProgressEndDate }}
                </p>

                <div class="d-flex justify-content-between align-items-center pt-3 border-top">
                    <span class="text-muted small">총 잔여량</span>
                    {% if item.total_stock >= 50 %}
                    <span class="stock-badge badge-success">{{ item.total_stock | format_stock }}</span>
                    {% elif item.total_stock > 0 %}
                    <span class="stock-badge badge-warning">{{ item.total_stock | format_stock }}</span>
                    {% else %}
                    <span class="stock-badge badge-danger">{{ item.total_stock | format_stock }}</span>
                    {% endif %}
                </div>
            </div>
            <div class="card-footer bg-transparent border-0 px-4 pb-4">
                <p class="text-muted smaller mb-0" style="font-size: 0.75rem;">
                    최근 업데이트: {{ item.last_updated.strftime('%m-%d %H:%M:%S') if item.last_updated else '-' }}
                </p>
            </div>
        </div>
    </div>
    {% endfor %}
</div>

{% if total_pages > 1 %}
<nav aria-label="Page navigation" class="mt-5">
    <ul class="pagination justify-content-center">
        <!-- Previous Button -->
        <li class="page-item {% if page == 1 %}disabled{% endif %}">
            <a class="page-link" href="/?page={{ page - 1 }}&q={{ q or '' }}&show_ended={{ 'true' if show_ended else 'false' }}" aria-label="Previous">
                <span aria-hidden="true">&laquo;</span>
            </a>
        </li>

        <!-- Page Numbers -->
        {% for p in range(1, total_pages + 1) %}
        <li class="page-item {% if p == page %}active{% endif %}">
            <a class="page-link" href="/?page={{ p }}&q={{ q or '' }}&show_ended={{ 'true' if show_ended else 'false' }}">
                {{ p }}
            </a>
        </li>
        {% endfor %}

        <!-- Next Button -->
        <li class="page-item {% if page == total_pages %}disabled{% endif %}">
            <a class="page-link" href="/?page={{ page + 1 }}&q={{ q or '' }}&show_ended={{ 'true' if show_ended else 'false' }}" aria-label="Next">
                <span aria-hidden="true">&raquo;</span>
            </a>
        </li>
    </ul>
</nav>
{% endif %}

<style>
.line-clamp-2 {
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}
.smaller { font-size: 0.8rem; }
</style>
<script>
    // Initialize Tooltips
    var tooltipTriggerList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'))
    var tooltipList = tooltipTriggerList.map(function (tooltipTriggerEl) {
        return new bootstrap.Tooltip(tooltipTriggerEl)
    })
</script>

{% endblock %}

